import { cn } from '@/utils/cn';
import { Component, createEffect, createSignal, For, mergeProps, on } from 'solid-js';
import type { InputOTPProps } from '../input.types';
import { getColor } from '@/utils/helper';

export const InputOTP: Component<InputOTPProps> = p => {
  p = mergeProps(
    {
      color: 'info',
      length: 6,
      inputMode: 'numeric',
      allowedChars: /^[0-9]$/,
      disabled: false,
    } as InputOTPProps,
    p,
  );

  const length = () => p.length || 6;
  const allowedChars = () => p.allowedChars || /^[0-9]$/;

  const [values, setValues] = createSignal<string[]>(Array(length()).fill(''));
  const [focusedIndex, setFocusedIndex] = createSignal<number | null>(null);

  let inputRefs: HTMLInputElement[] = [];

  createEffect(
    on(
      () => p.value,
      value => {
        if (value !== undefined) {
          const chars = value.split('').slice(0, length());
          const newValues = Array(length()).fill('');
          chars.forEach((char, i) => {
            newValues[i] = char;
          });
          setValues(newValues);
        }
      },
    ),
  );

  const getCombinedValue = () => values().join('');

  const notifyChange = (newValues: string[]) => {
    const combined = newValues.join('');
    p.onChange?.(combined);

    if (combined.length === length() && newValues.every(v => v !== '')) {
      p.onComplete?.(combined);
    }
  };

  const updateValue = (index: number, char: string) => {
    const newValues = [...values()];
    newValues[index] = char;
    setValues(newValues);
    notifyChange(newValues);
  };

  const focusInput = (index: number) => {
    if (index >= 0 && index < length() && inputRefs[index]) {
      inputRefs[index].focus();
    }
  };

  const getNextIndex = (currentIndex: number): number => {
    let nextIndex = (currentIndex + 1) % length();
    if (nextIndex === 0 && currentIndex === length() - 1) {
      const allFilled = values().every(v => v !== '');
      if (allFilled) {
        return -1;
      }
    }
    return nextIndex;
  };

  const handleInput = (index: number, e: InputEvent) => {
    const input = e.target as HTMLInputElement;
    const inputValue = input.value;
    input.value = '';

    if (!inputValue) return;
    const char = inputValue[inputValue.length - 1];

    if (!allowedChars().test(char)) return;

    updateValue(index, char);

    const nextIndex = getNextIndex(index);
    if (nextIndex === -1) {
      inputRefs[index]?.blur();
    } else {
      focusInput(nextIndex);
    }
  };

  const handlePaste = (index: number, e: ClipboardEvent) => {
    e.preventDefault();

    const pasteData = e.clipboardData?.getData('text') || '';
    if (!pasteData) return;

    const validChars = pasteData.split('').filter(char => allowedChars().test(char));
    if (validChars.length === 0) return;

    const newValues = [...values()];
    let lastFilledIndex = index;

    for (let i = 0; i < validChars.length && index + i < length(); i++) {
      newValues[index + i] = validChars[i];
      lastFilledIndex = index + i;
    }

    setValues(newValues);
    notifyChange(newValues);

    const allFilled = newValues.every(v => v !== '');
    if (allFilled) {
      inputRefs[lastFilledIndex]?.blur();
    } else {
      const nextEmptyIndex = newValues.findIndex((v, i) => i > lastFilledIndex && v === '');
      if (nextEmptyIndex !== -1) {
        focusInput(nextEmptyIndex);
      } else {
        focusInput(lastFilledIndex);
      }
    }
  };

  const handleKeyDown = (index: number, e: KeyboardEvent) => {
    switch (e.key) {
      case 'Backspace':
        e.preventDefault();
        if (values()[index]) {
          updateValue(index, '');
        } else if (index > 0) {
          updateValue(index - 1, '');
          focusInput(index - 1);
        }
        break;

      case 'Delete':
        e.preventDefault();
        updateValue(index, '');
        break;

      case 'ArrowLeft':
        e.preventDefault();
        if (index > 0) focusInput(index - 1);
        break;

      case 'ArrowRight':
        e.preventDefault();
        if (index < length() - 1) focusInput(index + 1);
        break;

      case 'Tab':
        e.preventDefault();
        if (e.shiftKey) {
          const prevIndex = index === 0 ? length() - 1 : index - 1;
          focusInput(prevIndex);
        } else {
          const nextIndex = (index + 1) % length();
          focusInput(nextIndex);
        }
        break;

      case 'ArrowUp':
      case 'ArrowDown':
        e.preventDefault();
        break;
    }
  };

  const handleFocus = (index: number) => {
    setFocusedIndex(index);
    inputRefs[index]?.select();
  };

  const handleBlur = (_index: number, e: FocusEvent) => {
    const relatedTarget = e.relatedTarget as HTMLElement;
    const isInternalFocus = inputRefs.some(ref => ref === relatedTarget);

    if (!isInternalFocus) {
      setFocusedIndex(null);
      p.onBlur?.(getCombinedValue());
    }
  };

  const handleContainerClick = (index: number) => {
    if (!p.disabled) focusInput(index);
  };

  return (
    <div
      class={cn(
        'op01',
        getColor(p.color!),
        p.class?.root,
        p.disabled && 'pointer-events-none opacity-50',
      )}
      role="group"
      aria-label="OTP Input"
    >
      <For each={Array(length()).fill(0)}>
        {(_, i) => (
          <>
            <div
              class={cn(
                'op04',
                focusedIndex() === i() ? 'op02' : 'border-c3 hover:border-c4',
                p.class?.inputWrap,
                p.disabled && 'border-c3',
              )}
              onClick={() => handleContainerClick(i())}
            >
              <input
                ref={el => (inputRefs[i()] = el)}
                type="text"
                inputMode={p.inputMode}
                maxLength={2}
                disabled={p.disabled}
                class={cn('op03', p.class?.input, p.disabled && 'cursor-not-allowed bg-gray-200')}
                autocomplete="one-time-code"
                aria-label={`OTP digit ${i() + 1}`}
                value={values()[i()] || ''}
                onInput={e => handleInput(i(), e)}
                onKeyDown={e => handleKeyDown(i(), e)}
                onPaste={e => handlePaste(i(), e)}
                onFocus={() => handleFocus(i())}
                onBlur={e => handleBlur(i(), e)}
              />
            </div>
            {p.separator && <div class="my-auto">{p.separator as Element}</div>}
          </>
        )}
      </For>
    </div>
  );
};

export default InputOTP;
